$path = "$env:APPDATA\.minecraft\launcher_profiles.json"
$path2 = "$env:APPDATA\.minecraft\launcher_profiles2.json"
$targetGameDir = "$env:APPDATA\.minecraft\ZSMP4"
$targetJavaDir = "$env:APPDATA\.minecraft\ZSMP4\java\bin\javaw.exe"
$json = Get-Content $path | ConvertFrom-Json
$json2 = Get-Content $path2 | ConvertFrom-Json
$newProfileData = [PSCustomObject]@{
    created       = Get-Date -Format "yyyy-MM-ddTHH:mm:ssZ"
    icon          = "data:image/png;base64,"
    lastUsed      = Get-Date -Format "yyyy-MM-ddTHH:mm:ssZ"
    lastVersionId = $json.profiles.neoforge.lastVersionId
    name          = "ZSMP4"
    type          = "custom"
    javaDir       = $targetJavaDir
    gameDir       = $targetGameDir
    javaArgs      = "-Xmx6G -XX:+UnlockExperimentalVMOptions -XX:+UseG1GC -XX:G1NewSizePercent=20 -XX:G1ReservePercent=20 -XX:MaxGCPauseMillis=50 -XX:G1HeapRegionSize=32M"
}
$json2.profiles | Add-Member -MemberType NoteProperty -Name "ZSMP4" -Value $newProfileData



$json | ConvertTo-Json -Depth 100 | Set-Content $path
